<?php
namespace App\Http\Controllers\KepalaDinas;
use App\Http\Controllers\Controller;use App\Services\Audit\AuditLogger;use App\Services\KepalaDinas\StrategicDashboardService;use Illuminate\Http\Request;
class KepalaDinasController extends Controller { public function dashboard(Request $request, StrategicDashboardService $service, AuditLogger $audit){ $indicators=$service->indicators(); $mapAggregate=$service->aggregateMapPoints(); $audit->log('kepala_dinas.dashboard.view',$request,'dashboard',null,[],['scope'=>'aggregate_only']); return view('pages.kepala-dinas.dashboard',compact('indicators','mapAggregate')); } public function report(Request $request, StrategicDashboardService $service, AuditLogger $audit){ $summary=['indicators'=>$service->indicators(),'map'=>$service->aggregateMapPoints(),'audit'=>$service->latestAuditSummary()]; $audit->log('kepala_dinas.report.view',$request,'report',null,[],['aggregate'=>true]); return view('pages.kepala-dinas.report',compact('summary')); } public function export(Request $request, StrategicDashboardService $service, AuditLogger $audit){ $validated=$request->validate(['reason'=>['required','string','max:250']]); $service->recordExport($request->user()->id,$validated['reason']); $audit->log('kepala_dinas.export.request',$request,'export',null,[],['reason'=>$validated['reason']]); return back()->with('status','Permintaan ekspor ringkasan dicatat.'); }}
